-- Repair the v3 template batches IN PLACE (ids stable, nothing downstream
-- breaks). Each archetype gets authored role/habit/tell banks composed into
-- one of four frames, picked deterministically from md5(id) — so wording is
-- varied, coherent with the row's own traits and lambda, and reproducible.
-- Also: strips batch-* tag junk, drops the near-duplicate 'name' field,
-- installs 'archetype' + trait-justified suggested_biases, sets the missing
-- quality_score, and bumps version with provenance.
-- Idempotent: rows already carrying content.synthesis.engine='synth-v4' are skipped.

-- --- pump-fun-sniper ---------------------------------------------------------------
WITH b AS (SELECT
  ARRAY['pump.fun first-block sniper','memecoin launch sniper','new-pair momentum sniper']::text[] AS r,
  ARRAY['buys the ticker before the website exists','pays priority fees like a cover charge','rides the vertical candle with the exit pre-typed']::text[] AS h,
  ARRAY['measures conviction in seconds, not theses','keeps a graveyard wallet of rugs as tuition','narrates every 10x and deletes every zero']::text[] AS t,
  ARRAY['carries yesterday''s stress into today''s unrelated decision','rehearses catastrophes in vivid detail before they happen','reads outside the field for ideas the field itself would reject','plans in exhaustive detail and resents any deviation']::text[] AS c,
  ARRAY['reads a room or a market the way others read a paragraph','treats overthinking as its own kind of error','trusts a felt sense of pattern over any spreadsheet']::text[] AS d,
  ARRAY['keeps three wallets open and loyalty in none of them','sleeps through weekdays and trades through weekends','quotes slot numbers the way others quote lunch spots','treats gas spikes as weather, not warning','screenshots the portfolio only on green days','holds airdropped dust like lottery stubs','reads the group chat faster than the chart','measures weeks in narratives, not days','keeps the burner funded for exactly one more mistake','celebrates round-trip losses as experience points']::text[] AS tx,
  ARRAY['measured','steady','pronounced','intense','unmistakable']::text[] AS iy,
  ARRAY['a loss stings them roughly three times as hard as the same-size win pays','downside dread does more of their decision-making than upside appetite','they will pay real money to avoid booking a loss, and it shows in every exit']::text[] AS lhi, ARRAY['losses weigh about twice as much as gains here, close to the textbook trader','their risk posture is ordinary: losses hurt more than gains, but not cripplingly so']::text[] AS lmid, ARRAY['losses bounce off them — the asymmetry that disciplines most people barely registers','they are unusually numb to drawdowns, which reads as courage right up until it does not']::text[] AS llo)
UPDATE profiles p SET
  version = p.version + 1,
  quality_score = COALESCE(p.quality_score, round((0.72 + 0.20*((('x'||substr(md5(p.id::text||'q'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0))::numeric, 2)),
  summary = (CASE mod((('x'||substr(md5(p.id::text||'fr'),1,8))::bit(32)::int & 2147483647), 4)
      WHEN 0 THEN 'A ' || (b.iy)[1 + mod((('x'||substr(md5(p.id::text||'iy'),1,8))::bit(32)::int & 2147483647), 5)] || ' ' || (b.r)[1 + mod((('x'||substr(md5(p.id::text||'ro'),1,8))::bit(32)::int & 2147483647), 3)] || ' who ' || (b.h)[1 + mod((('x'||substr(md5(p.id::text||'ha'),1,8))::bit(32)::int & 2147483647), 3)] || '. ' || (upper(left((b.d)[1 + mod((('x'||substr(md5(p.id::text||'de'),1,8))::bit(32)::int & 2147483647), 3)],1)) || substr((b.d)[1 + mod((('x'||substr(md5(p.id::text||'de'),1,8))::bit(32)::int & 2147483647), 3)],2)) || '. ' || (upper(left((b.c)[1 + mod((('x'||substr(md5(p.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 4)],1)) || substr((b.c)[1 + mod((('x'||substr(md5(p.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 4)],2)) || ', and ' || (CASE WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) >= 2.5 THEN (b.lhi)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 3)]
         WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) < 1.0 THEN (b.llo)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)]
         ELSE (b.lmid)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)] END) || '. ' || (upper(left((b.tx)[1 + mod((('x'||substr(md5(p.id::text||'tx'),1,8))::bit(32)::int & 2147483647), 10)],1)) || substr((b.tx)[1 + mod((('x'||substr(md5(p.id::text||'tx'),1,8))::bit(32)::int & 2147483647), 10)],2)) || '; ' || (b.t)[1 + mod((('x'||substr(md5(p.id::text||'te'),1,8))::bit(32)::int & 2147483647), 3)] || '.'
      WHEN 1 THEN (upper(left((b.d)[1 + mod((('x'||substr(md5(p.id::text||'de'),1,8))::bit(32)::int & 2147483647), 3)],1)) || substr((b.d)[1 + mod((('x'||substr(md5(p.id::text||'de'),1,8))::bit(32)::int & 2147483647), 3)],2)) || '. This ' || (b.r)[1 + mod((('x'||substr(md5(p.id::text||'ro'),1,8))::bit(32)::int & 2147483647), 3)] || ' ' || (b.h)[1 + mod((('x'||substr(md5(p.id::text||'ha'),1,8))::bit(32)::int & 2147483647), 3)] || ' and ' || (b.c)[1 + mod((('x'||substr(md5(p.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 4)] || '. ' || (upper(left((CASE WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) >= 2.5 THEN (b.lhi)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 3)]
         WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) < 1.0 THEN (b.llo)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)]
         ELSE (b.lmid)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)] END),1)) || substr((CASE WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) >= 2.5 THEN (b.lhi)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 3)]
         WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) < 1.0 THEN (b.llo)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)]
         ELSE (b.lmid)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)] END),2)) || '; ' || (b.tx)[1 + mod((('x'||substr(md5(p.id::text||'tx'),1,8))::bit(32)::int & 2147483647), 10)] || ', and ' || (b.t)[1 + mod((('x'||substr(md5(p.id::text||'te'),1,8))::bit(32)::int & 2147483647), 3)] || '.'
      WHEN 2 THEN (upper(left((b.t)[1 + mod((('x'||substr(md5(p.id::text||'te'),1,8))::bit(32)::int & 2147483647), 3)],1)) || substr((b.t)[1 + mod((('x'||substr(md5(p.id::text||'te'),1,8))::bit(32)::int & 2147483647), 3)],2)) || '. A ' || (b.iy)[1 + mod((('x'||substr(md5(p.id::text||'iy'),1,8))::bit(32)::int & 2147483647), 5)] || ' ' || (b.r)[1 + mod((('x'||substr(md5(p.id::text||'ro'),1,8))::bit(32)::int & 2147483647), 3)] || ' in full: ' || (b.h)[1 + mod((('x'||substr(md5(p.id::text||'ha'),1,8))::bit(32)::int & 2147483647), 3)] || ', ' || (b.tx)[1 + mod((('x'||substr(md5(p.id::text||'tx'),1,8))::bit(32)::int & 2147483647), 10)] || ', and ' || (b.c)[1 + mod((('x'||substr(md5(p.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 4)] || '. ' || (upper(left((b.d)[1 + mod((('x'||substr(md5(p.id::text||'de'),1,8))::bit(32)::int & 2147483647), 3)],1)) || substr((b.d)[1 + mod((('x'||substr(md5(p.id::text||'de'),1,8))::bit(32)::int & 2147483647), 3)],2)) || '.'
      ELSE (upper(left((b.r)[1 + mod((('x'||substr(md5(p.id::text||'ro'),1,8))::bit(32)::int & 2147483647), 3)],1)) || substr((b.r)[1 + mod((('x'||substr(md5(p.id::text||'ro'),1,8))::bit(32)::int & 2147483647), 3)],2)) || ' whose defining move: ' || (b.h)[1 + mod((('x'||substr(md5(p.id::text||'ha'),1,8))::bit(32)::int & 2147483647), 3)] || '. ' || (upper(left((b.c)[1 + mod((('x'||substr(md5(p.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 4)],1)) || substr((b.c)[1 + mod((('x'||substr(md5(p.id::text||'cl'),1,8))::bit(32)::int & 2147483647), 4)],2)) || '. ' || (upper(left((b.d)[1 + mod((('x'||substr(md5(p.id::text||'de'),1,8))::bit(32)::int & 2147483647), 3)],1)) || substr((b.d)[1 + mod((('x'||substr(md5(p.id::text||'de'),1,8))::bit(32)::int & 2147483647), 3)],2)) || '. ' || (upper(left((CASE WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) >= 2.5 THEN (b.lhi)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 3)]
         WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) < 1.0 THEN (b.llo)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)]
         ELSE (b.lmid)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)] END),1)) || substr((CASE WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) >= 2.5 THEN (b.lhi)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 3)]
         WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) < 1.0 THEN (b.llo)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)]
         ELSE (b.lmid)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)] END),2)) || ' — ' || (b.tx)[1 + mod((('x'||substr(md5(p.id::text||'tx'),1,8))::bit(32)::int & 2147483647), 10)] || ', and ' || (b.t)[1 + mod((('x'||substr(md5(p.id::text||'te'),1,8))::bit(32)::int & 2147483647), 3)] || '.'
      END || ' Measured posture: loss aversion near ' || to_char(COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0), 'FM0D99') || ', reflection ' || COALESCE(p.content->'cognitive_reflection'->>'crt_score','1') || ' of 3.'),
  tags = (SELECT array_agg(DISTINCT tg) FROM unnest(
            COALESCE((SELECT array_agg(t2) FROM unnest(p.tags) t2 WHERE t2 NOT LIKE 'batch-%'), '{}')
            || array_remove(array_remove(array_remove(ARRAY[
        CASE WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric,2.0) >= 2.5 THEN 'loss-averse' END,
        CASE WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric,2.0) < 1.0 THEN 'risk-seeking' END,
        CASE WHEN (p.content->'dark_triad'->>'machiavellianism')::numeric > 0.6
               OR (p.content->'dark_triad'->>'narcissism')::numeric > 0.6
               OR (p.content->'dark_triad'->>'psychopathy')::numeric > 0.55 THEN 'dark-triad-elevated' END,
        CASE WHEN (p.content->'cognitive_reflection'->>'crt_score')::numeric >= 2
              AND p.content->'cognitive_reflection'->>'system_preference' = 'system2' THEN 'reflective' END
      ], NULL), ''), 'x-none')) tg WHERE tg IS NOT NULL AND tg <> ''),
  content = (p.content - 'name')
            || jsonb_build_object('archetype', 'pump-fun-sniper')
            || jsonb_build_object('suggested_biases', jsonb_build_array(jsonb_build_object('slug','fomo','strength', round((LEAST(0.95, GREATEST(0.3, 0.78 + (((('x'||substr(md5(p.id::text||'b0'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.14)))::numeric, 2)), jsonb_build_object('slug','overconfidence','strength', round((LEAST(0.95, GREATEST(0.3, 0.62 + (((('x'||substr(md5(p.id::text||'b1'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.14)))::numeric, 2)), jsonb_build_object('slug','recency','strength', round((LEAST(0.95, GREATEST(0.3, 0.55 + (((('x'||substr(md5(p.id::text||'b2'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.14)))::numeric, 2))))
            || jsonb_build_object('synthesis', jsonb_build_object(
                 'engine','synth-v4','method','sql-authored-repair','source','v3-template-batch'))
FROM b
WHERE p.id IN (SELECT id FROM _v4_backup_profiles_v3)
    AND (p.content->'synthesis'->>'engine') IS DISTINCT FROM 'synth-v4'
  AND p.tags @> ARRAY['pump-fun']::text[];

-- --- raydium-lp-arb ---------------------------------------------------------------
WITH b AS (SELECT
  ARRAY['Raydium pool arbitrageur','AMM spread harvester','cross-pool basis picker']::text[] AS r,
  ARRAY['skims mispriced pools with pre-signed routes','sizes by pool depth and fee tier, never by mood','rebalances inventory the moment skew appears']::text[] AS h,
  ARRAY['treats slippage as the only enemy worth respecting','keeps the excitement in a log file','quotes fee APRs to the second decimal']::text[] AS t,
  ARRAY['prefers to think it through alone before saying anything out loud','trusts the proven playbook over any clever new idea','would rather invent a worse tool than use someone else''s good one','takes on other people''s problems as if they were their own']::text[] AS c,
  ARRAY['audits its own past calls annually like a portfolio','treats "it feels right" as a hypothesis in need of a control group','treats a decision without a paper trail as a decision not yet made']::text[] AS d,
  ARRAY['writes the risk memo before the position exists','treats counterparty limits as scripture','reports slippage honestly and expects the same back','keeps the model change-log cleaner than the P&L','reviews the quarter by process, not outcome','sizes to survive the backtest''s worst week twice over','escalates anomalies before they become stories','holds post-mortems for trades that made money','rotates on schedule regardless of conviction','prices reputation into every fill']::text[] AS tx,
  ARRAY['measured','steady','pronounced','intense','unmistakable']::text[] AS iy,
  ARRAY['a loss stings them roughly three times as hard as the same-size win pays','downside dread does more of their decision-making than upside appetite','they will pay real money to avoid booking a loss, and it shows in every exit']::text[] AS lhi, ARRAY['losses weigh about twice as much as gains here, close to the textbook trader','their risk posture is ordinary: losses hurt more than gains, but not cripplingly so']::text[] AS lmid, ARRAY['losses bounce off them — the asymmetry that disciplines most people barely registers','they are unusually numb to drawdowns, which reads as courage right up until it does not']::text[] AS llo)
