  content = (p.content - 'name')
            || jsonb_build_object('archetype', 'retail-swing-discipline')
            || jsonb_build_object('suggested_biases', jsonb_build_array(jsonb_build_object('slug','anchoring','strength', round((LEAST(0.95, GREATEST(0.3, 0.5 + (((('x'||substr(md5(p.id::text||'b0'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.14)))::numeric, 2)), jsonb_build_object('slug','confirmation','strength', round((LEAST(0.95, GREATEST(0.3, 0.48 + (((('x'||substr(md5(p.id::text||'b1'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.14)))::numeric, 2))))
            || jsonb_build_object('synthesis', jsonb_build_object(
                 'engine','synth-v4','method','sql-authored-repair','source','v3-template-batch'))
FROM b
WHERE p.id IN (SELECT id FROM _v4_backup_profiles_v3)
    AND (p.content->'synthesis'->>'engine') IS DISTINCT FROM 'synth-v4'
  AND p.tags @> ARRAY['swing-trader']::text[];

