WITH b AS (SELECT
  ARRAY['social-sentiment follower','feed-driven retail trader','consensus surfer']::text[] AS r,
  ARRAY['buys what the timeline agrees on','waits for three influencers to align before entering','exits when the group chat goes quiet']::text[] AS h,
  ARRAY['conviction is crowdsourced hourly','always one candle behind the narrative','holds only what is popular to hold']::text[] AS t,
  ARRAY['finds a full day of meetings more draining than a full day of work','notices the one thing that could go wrong before the nine that could go right','treats a missed deadline as a personal failure regardless of cause','meets a stranger and leaves with a plan']::text[] AS c,
  ARRAY['feels the weight of a decision lighten the moment someone else co-signs it','phones a friend on decisions it has already privately made','needs the room''s approval more than it needs to be right']::text[] AS d,
  ARRAY['checks the app in line for coffee and regrets it','keeps a watchlist longer than a grocery list','trades around earnings like planning around storms','moves the mental stop rather than the real one','reads one bear thread and one bull thread and picks by mood','keeps last year''s statement unopened in a drawer','talks entries at dinner, never exits','sizes positions by paycheck cycle','has the support line memorized from the last outage','checks after-hours prices from bed with one eye']::text[] AS tx,
  ARRAY['measured','steady','pronounced','intense','unmistakable']::text[] AS iy,
  ARRAY['a loss stings them roughly three times as hard as the same-size win pays','downside dread does more of their decision-making than upside appetite','they will pay real money to avoid booking a loss, and it shows in every exit']::text[] AS lhi, ARRAY['losses weigh about twice as much as gains here, close to the textbook trader','their risk posture is ordinary: losses hurt more than gains, but not cripplingly so']::text[] AS lmid, ARRAY['losses bounce off them — the asymmetry that disciplines most people barely registers','they are unusually numb to drawdowns, which reads as courage right up until it does not']::text[] AS llo)
