         WHEN COALESCE((p.content->'prospect_theory'->>'lambda')::numeric, 2.0) < 1.0 THEN (b.llo)[1 + mod((('x'||substr(md5(p.id::text||'lam'),1,8))::bit(32)::int & 2147483647), 2)]
