            || jsonb_build_object('archetype', 'defi-yield-whale')
            || jsonb_build_object('suggested_biases', jsonb_build_array(jsonb_build_object('slug','status-quo','strength', round((LEAST(0.95, GREATEST(0.3, 0.45 + (((('x'||substr(md5(p.id::text||'b0'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.14)))::numeric, 2)), jsonb_build_object('slug','ambiguity-aversion','strength', round((LEAST(0.95, GREATEST(0.3, 0.55 + (((('x'||substr(md5(p.id::text||'b1'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.14)))::numeric, 2)), jsonb_build_object('slug','pseudocertainty','strength', round((LEAST(0.95, GREATEST(0.3, 0.5 + (((('x'||substr(md5(p.id::text||'b2'),1,8))::bit(32)::int & 2147483647)::numeric / 2147483647.0) - 0.5)*0.14)))::numeric, 2))))
